import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"25. Fixed Term Employment","description":"","frontmatter":{"title":"25. Fixed Term Employment","eba":"Health Allied & Managers Admin 2021-2025","topics":["employment"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/employment-types/25-fixed-term-employment.md","filePath":"ebas/has-managers-admin/common-terms/employment-types/25-fixed-term-employment.md"}'),a={name:"ebas/has-managers-admin/common-terms/employment-types/25-fixed-term-employment.md"};function s(i,e,m,p,l,d){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_25-fixed-term-employment" tabindex="-1">25. Fixed Term Employment <a class="header-anchor" href="#_25-fixed-term-employment" aria-label="Permalink to &quot;25. Fixed Term Employment&quot;">​</a></h1><p><strong>25.1</strong> A fixed term Employee is an Employee who is employed for a specified period of time, which period is known at the commencement of the contract, or for a specified task such as a project or replacement of an absent employee.</p><p><strong>25.2</strong> Subject to clause 25.4, fixed term employment will not be used to fill an ongoing position, or offered through consecutive fixed term employment contracts for work that is otherwise ongoing.</p><p><strong>25.3</strong> Examples of where fixed term employment may be appropriate include:</p><p><strong>(a)</strong> Graduate positions;</p><p><strong>(b)</strong> Long term WorkCover replacement;</p><p><strong>(c)</strong> Special Projects or a body of work with clear parameters determined in advance by the Employer with the intent to deliver a specified outcome within an anticipated timeframe;</p><p><strong>(d)</strong> Backfill including for extended leave (such as Parental Leave and Long Service Leave), to support flexible working arrangements, temporary assignment or secondment Note: In this context, backfill to support flexible working arrangements does not refer to the Employee on the flexible working arrangement, but instead to an arrangement to work hours that arise</p><p>PART C – TYPES OF EMPLOYMENT AND TERMINATION OF EMPLOYMENT</p><p>from a flexible work arrangement that includes a temporary reduction in hours.</p><p><strong>25.4</strong> Where there is a need to continue employment on a fixed term basis beyond the original contract period, further fixed term contracts may be offered only where the arrangement continues to be consistent with subclause 25.2 and</p><p><strong>25.3</strong> above.</p><p><strong>25.5</strong> Where an Employee disputes a matter pertaining to this Clause 25 - Fixed Term Employment, the Employee should raise the concerns with their immediate supervisor or line manager in the first instance and seek to resolve the issue.</p><p><strong>(a)</strong> If no resolution can be achieved, the Employee may:</p><p><strong>(i)</strong> Seek to have the matter tabled at the Agreement Implementation Committee, or,</p><p><strong>(ii)</strong> utilise the Dispute Resolution Procedure set out in <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">clause 17</a> of this Agreement.</p><p>Plain language terms: contract, fixed-term.</p>',17)])])}const g=t(a,[["render",s]]);export{h as __pageData,g as default};
